#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    if (x[0] < y[0]) return -1;
    if (x[0] > y[0]) return 1;
    if (x[1] < y[1]) return -1;
    if (x[1] > y[1]) return 1;
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, P;
        scanf("%d %d %d", &N, &K, &P);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int pairs[1 << K][2];
        for (int x = 0; x < (1 << K); x++) {
            int inversions = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    if ((A[i] ^ x) > (A[j] ^ x)) {
                        inversions++;
                    }
                }
            }
            pairs[x][0] = inversions;
            pairs[x][1] = x;
        }
        qsort(pairs, (1 << K), sizeof(pairs[0]), compare);
        printf("%d\n", pairs[P - 1][1]);
    }
    return 0;
}

