import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int P = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            Pair[] pairs = new Pair[1 << K];
            for (int x = 0; x < (1 << K); x++) {
                int inversions = 0;
                for (int i = 0; i < N; i++) {
                    for (int j = i + 1; j < N; j++) {
                        if ((A[i] ^ x) > (A[j] ^ x)) {
                            inversions++;
                        }
                    }
                }
                pairs[x] = new Pair(inversions, x);
            }
            Arrays.sort(pairs);
            System.out.println(pairs[P - 1].y);
        }
    }
}

class Pair implements Comparable<Pair> {
    int x;
    int y;
    Pair(int x, int y) {
        this.x = x;
        this.y = y;
    }
    @Override
    public int compareTo(Pair o) {
        if (x < o.x) return -1;
        if (x > o.x) return 1;
        if (y < o.y) return -1;
        if (y > o.y) return 1;
        return 0;
    }
}

